function solve(nums, target) {
    const n = nums.length;

    // dp[i][j] will store the minimum number of elements to remove from nums[0...i-1]
    // such that the XOR sum of the remaining elements is j.
    // Since the maximum possible XOR sum is less than 2^14 (as max num is 10^4 < 2^14),
    // we can use a bitmask for the XOR sum up to 16384.
